INSERT INTO product (name, stock, price, content, created_at, updated_at) VALUES
('MacBook Pro 16인치', 50, 3590000, 'Apple M3 Pro 칩이 탑재된 최신 MacBook Pro입니다. 뛰어난 성능과 긴 배터리 수명을 자랑하며, 개발자와 크리에이티브 전문가에게 최적화되어 있습니다.', NOW(), NOW()),
('iPhone 15 Pro', 120, 1550000, '티타늄 소재로 제작된 프리미엄 스마트폰입니다. A17 Pro 칩과 향상된 카메라 시스템으로 프로페셔널한 사진과 영상 촬영이 가능합니다.', NOW(), NOW()),
('iPad Air 5세대', 80, 899000, 'M1 칩이 탑재된 태블릿으로 뛰어난 성능을 제공합니다. Apple Pencil과 Magic Keyboard를 지원하여 생산성과 창작 활동에 최적입니다.', NOW(), NOW()),
('AirPods Pro 2세대', 200, 359000, '활성 소음 차단 기능이 강화된 무선 이어폰입니다. 공간 오디오와 적응형 투명 모드로 몰입감 있는 오디오 경험을 제공합니다.', NOW(), NOW()),
('Apple Watch Series 9', 150, 599000, '가장 진보된 Apple Watch입니다. 더 빠른 S9 칩과 새로운 제스처 기능으로 손쉬운 조작이 가능합니다.', NOW(), NOW()),
('Samsung Galaxy S24 Ultra', 90, 1698000, '200MP 카메라와 S펜이 내장된 플래그십 스마트폰입니다. AI 기능과 뛰어난 디스플레이로 최고의 사용자 경험을 제공합니다.', NOW(), NOW()),
('Galaxy Tab S9 Ultra', 60, 1499000, '14.6인치 대화면 태블릿으로 멀티태스킹과 콘텐츠 소비에 최적화되어 있습니다. S펜이 포함되어 있어 디지털 노트 작성과 그림 그리기에 적합합니다.', NOW(), NOW()),
('Galaxy Buds2 Pro', 180, 229000, 'ANC 기능과 360 Audio를 지원하는 프리미엄 무선 이어폰입니다. 편안한 착용감과 뛰어난 음질을 자랑합니다.', NOW(), NOW()),
('Nintendo Switch OLED', 75, 459000, '7인치 OLED 디스플레이가 탑재된 휴대용 게임 콘솔입니다. 선명한 화면과 향상된 오디오로 게임을 더욱 생생하게 즐길 수 있습니다.', NOW(), NOW()),
('PlayStation 5', 40, 698000, '차세대 게임 콘솔로 4K 게이밍과 초고속 SSD를 지원합니다. DualSense 컨트롤러의 햅틱 피드백으로 몰입감 있는 게임 플레이가 가능합니다.', NOW(), NOW()),
('Xbox Series X', 45, 648000, '12테라플롭스의 강력한 성능을 자랑하는 게임 콘솔입니다. 4K/120fps 게이밍과 빠른 로딩 시간을 제공합니다.', NOW(), NOW()),
('LG 그램 17인치', 35, 2190000, '초경량 17인치 노트북으로 뛰어난 휴대성과 긴 배터리 수명을 자랑합니다. 대화면에서 편리한 작업이 가능합니다.', NOW(), NOW()),
('Dell XPS 13', 55, 1890000, '프리미엄 울트라북으로 InfinityEdge 디스플레이와 뛰어난 빌드 품질을 자랑합니다. 비즈니스와 개인 사용 모두에 적합합니다.', NOW(), NOW()),
('Surface Pro 9', 65, 1649000, '2-in-1 태블릿 PC로 노트북과 태블릿의 장점을 모두 제공합니다. Surface Pen과 Type Cover로 생산성을 극대화할 수 있습니다.', NOW(), NOW()),
('Magic Mouse', 100, 109000, '매끄러운 Multi-Touch 표면을 가진 Apple 마우스입니다. 직관적인 제스처로 Mac과 완벽하게 호환됩니다.', NOW(), NOW()),
('Magic Keyboard', 85, 149000, 'Mac과 iPad를 위한 무선 키보드입니다. 안정적인 가위식 키 메커니즘과 내장 배터리로 편리한 타이핑 경험을 제공합니다.', NOW(), NOW()),
('AirTag 4팩', 300, 149000, '분실물 추적을 위한 소형 디바이스입니다. 나의 찾기 네트워크를 통해 전 세계 어디서나 소중한 물건을 찾을 수 있습니다.', NOW(), NOW()),
('Logitech MX Master 3S', 120, 159000, '프리미엄 무선 마우스로 정밀한 센서와 조용한 클릭을 제공합니다. 생산성 향상을 위한 다양한 커스터마이징 옵션을 지원합니다.', NOW(), NOW()),
('Razer DeathAdder V3', 95, 89000, '게이밍에 최적화된 인체공학적 마우스입니다. 30,000 DPI 센서와 90시간 배터리 수명으로 장시간 게임 플레이가 가능합니다.', NOW(), NOW()),
('Sony WH-1000XM5', 110, 449000, '업계 최고 수준의 노이즈 캔슬링 헤드폰입니다. 30시간 재생과 뛰어난 음질로 음악과 통화 품질이 모두 뛰어납니다.', NOW(), NOW()),
('Bose QuietComfort 45', 88, 429000, '편안한 착용감과 뛰어난 노이즈 캔슬링 기능을 제공하는 헤드폰입니다. 장시간 사용해도 피로하지 않는 디자인이 특징입니다.', NOW(), NOW()),
('JBL Charge 5', 200, 199000, '강력한 사운드와 20시간 재생이 가능한 포터블 스피커입니다. IP67 방수 등급으로 야외 활동에 최적입니다.', NOW(), NOW()),
('Anker PowerCore 26800', 250, 79000, '대용량 26800mAh 보조배터리입니다. 3개의 USB 포트로 여러 기기를 동시에 고속 충전할 수 있습니다.', NOW(), NOW()),
('삼성 970 EVO Plus 1TB', 150, 159000, '고성능 NVMe SSD로 뛰어난 속도와 안정성을 제공합니다. 게임 로딩과 대용량 파일 작업에 최적화되어 있습니다.', NOW(), NOW()),
('WD Black SN850X 2TB', 80, 329000, '게이밍에 최적화된 PCIe 4.0 SSD입니다. 초고속 데이터 전송으로 게임과 크리에이티브 작업의 성능을 향상시킵니다.', NOW(), NOW());